public function GetAttributeFlags($sAttCode, &$aReasons = array(), $sTargetState = '')
{
	if ($sAttCode == 'private_log' && !UserRights::IsAdministrator())
	{
		static $bRestricted = null;
		if ($bRestricted === null)
		{
			$bRestricted = false;
			try
			{
				$iUserId = (int) UserRights::GetUserId();
				$oSearch = DBSearch::FromOQL(
					"SELECT URP_UserProfile AS up JOIN URP_Profiles AS p ON up.profileid = p.id" .
					" WHERE up.userid = :uid AND p.name IN ('Support Agent', 'Service Desk Agent')"
				);
				$oSearch->AllowAllData();
				$oSet = new DBObjectSet($oSearch, array(), array('uid' => $iUserId));
				$bRestricted = ($oSet->Count() > 0);
			}
			catch (Exception $e)
			{
				// ante error, dejar sin restricción
			}
		}
		if ($bRestricted)
		{
			return (OPT_ATT_READONLY | parent::GetAttributeFlags($sAttCode, $aReasons, $sTargetState));
		}
	}
	return parent::GetAttributeFlags($sAttCode, $aReasons, $sTargetState);
}

